INSERT INTO `movies` VALUES (1,'신세계','\"너, 나하고 일 하나 같이 하자\" 경찰청 수사 기획과 강과장(최민식)은 국내 최대 범죄 조직인 \'골드문\'이 기업형 조직으로 그 세력이 점점 확장되자 신입경찰 이자성(이정재)에게 잠입 수사를 명한다. 그리고 8년, 자성은 골드문의 2인자이자 그룹 실세인 정청(황정민)의 오른팔이 되기에 이른다. \"우리 브라더는 그냥 딱, 이 형님만 믿으면 돼야!\" 골드문 회장이 갑자기 사망하자, 강과장(최민식)은 후계자 결정에 직접 개입하는 \'신세계\' 작전을 설계한다. 피도 눈물도 없는 후계자 전쟁의 한 가운데, 정청(황정민)은 8년 전, 고향 여수에서 처음 만나 지금까지 친형제처럼 모든 순간을 함께 해 온 자성(이정재)에게 더욱 강한 신뢰를 보낸다. \"약속 했잖습니까... 이번엔 진짜 끝이라고\" 한편, 작전의 성공만 생각하는 강과장(최민식)은 계속해서 자성(이정재)의 목을 조여만 간다. 시시각각 신분이 노출될 위기에 처한 자성(이정재)은 언제 자신을 배신할 지 모르는 경찰과, 형제의 의리로 대하는 정청(황정민) 사이에서 갈등하게 되는데…',120,'2024-05-01',5,'/img/영화_신세계_포스터.jpg'),(2,'파묘','미국 LA, 거액의 의뢰를 받은 무당 ‘화림’(김고은)과 ‘봉길’(이도현)은 기이한 병이 대물림되는 집안의 장손을 만난다. 조상의 묫자리가 화근임을 알아챈 ‘화림’은 이장을 권하고, 돈 냄새를 맡은 최고의 풍수사 ‘상덕’(최민식)과 장의사 ‘영근’(유해진)이 합류한다. “전부 잘 알 거야… 묘 하나 잘못 건들면 어떻게 되는지” 절대 사람이 묻힐 수 없는 악지에 자리한 기이한 묘. ‘상덕’은 불길한 기운을 느끼고 제안을 거절하지만, ‘화림’의 설득으로 결국 파묘가 시작되고… 나와서는 안될 것이 나왔다.',125,'2024-04-15',4,'/img/파묘.jpg'),(3,'인사이드 아웃 2','<인사이드 아웃> 새로운 감정과 함께 돌아오다! 13살이 된 라일리의 행복을 위해 매일 바쁘게 머릿속 감정 컨트롤 본부를 운영하는 ‘기쁨’, ‘슬픔’, ‘버럭’, ‘까칠’, ‘소심’. 그러던 어느 날, 낯선 감정인 ‘불안’, ‘당황’, ‘따분’, ‘부럽’이가 본부에 등장하고, 언제나 최악의 상황을 대비하며 제멋대로인 ‘불안’이와 기존 감정들은 계속 충돌한다. 결국 새로운 감정들에 의해 본부에서 쫓겨나게 된 기존 감정들은 다시 본부로 돌아가기 위해 위험천만한 모험을 시작하는데… 전 세계를 공감으로 물들인 유쾌한 상상이 다시 시작된다!',110,'2024-04-03',5,'/img/인사이드아웃.webp'),(4,'서울의 봄','1979년 12월 12일, 수도 서울 군사반란 발생 그날, 대한민국의 운명이 바뀌었다 대한민국을 뒤흔든 10월 26일 이후, 서울에 새로운 바람이 불어온 것도 잠시 12월 12일, 보안사령관 전두광이 반란을 일으키고 군 내 사조직을 총동원하여 최전선의 전방부대까지 서울로 불러들인다. 권력에 눈이 먼 전두광의 반란군과 이에 맞선 수도경비사령관 이태신을 비롯한 진압군 사이, 일촉즉발의 9시간이 흘러가는데… 목숨을 건 두 세력의 팽팽한 대립 오늘 밤, 대한민국 수도에서 가장 치열한 전쟁이 펼쳐진다!',130,'2024-01-14',4,'/img/서울의봄.jpg'),(5,'범죄도시 4','신종 마약 사건 3년 뒤, 괴물형사 ‘마석도’(마동석)와 서울 광수대는 배달앱을 이용한 마약 판매 사건을 수사하던 중 수배 중인 앱 개발자가 필리핀에서 사망한 사건이 대규모 온라인 불법 도박 조직과 연관되어 있음을 알아낸다. 필리핀에 거점을 두고 납치, 감금, 폭행, 살인 등으로 대한민국 온라인 불법 도박 시장을 장악한 특수부대 용병 출신의 빌런 ‘백창기’(김무열)와 한국에서 더 큰 판을 짜고 있는 IT업계 천재 CEO ‘장동철’(이동휘). ‘마석도’는 더 커진 판을 잡기 위해 ‘장이수’(박지환)에게 뜻밖의 협력을 제안하고 광역수사대는 물론, 사이버수사대까지 합류해 범죄를 소탕하기 시작하는데… 나쁜 놈 잡는데 국경도 영역도 제한 없다! 업그레이드 소탕 작전! 거침없이 싹 쓸어버린다!',130,'2024-02-04',5,'/img/범죄도시4.jpg'),(6,'신세계','너, 나하고 일 하나 같이 하자 경찰청 수사 기획과 강과장(최민식)은 국내 최대 범죄 조직인 \'골드문\'이 기업형 조직으로 그 세력이 점점 확장되자 신입경찰 이자성(이정재)에게 잠입 수사를 명한다. 그리고 8년, 자성은 골드문의 2인자이자 그룹 실세인 정청(황 정민)의 오른팔이 되기에 이른다. 우리 브라더는 그냥 딱, 이 형님만 믿으면 돼야! 골드문 회장이 갑자기 사망하자, 강과장(최민식)은 후계자 결정에 직접 개입하는 \'신세계\' 작전을 설계한다. 피도 눈물도 없는 후계자 전쟁의 한 가운데, 정청(황정민)은 8년 전, 고향 여수에서 처음 만나 지금까지 친형제처럼 모든 순간을 함께 해 온 자성(이정재)에게 더욱 강한 신뢰를 보낸다. 약속 했잖습니까... 이번엔 진짜 끝이라고 한편, 작전의 성공만 생각하는 강과장(최민식)은 계속해서 자성(이정재)의 목을 조여만 간다. 시시각각 신분이 노출될 위기에 처한 자성(이정재)은 언제 자신을 배신할 지 모르는 경찰과, 형제의 의리로 대하는 정청(황정민) 사이에서 갈등하게 되는데…',120,'2024-05-01',5,'/img/영화_신세계_포스터.jpg'),(7,'기생충','박 사장(이선균)네에 아들 기우(최우식)가 과외선생으로 들어가게 되면서 시작되는 두 가족의 만남과 갈등을 그린 영화. 이들 사이에서 벌어지는 일련의 사건들이 유쾌하고도 서스펜스 넘치게 전개된다.',132,'2019-05-30',5,'/img/영화_기생충_포스터.jpg'),(8,'내부자들','이병헌이 열연하는 정치 스릴러 영화. 권력과 언론, 그리고 그들 사이에 얽힌 음모를 다루며, 긴장감 넘치는 스토리가 전개된다.',157,'2015-11-19',5,'/img/영화_내부자들_포스터.jpg'),(9,'올드보이','평범한 가장이었던 오대수(최민식)가 어느 날 갑자기 납치되어 15년간 감금된 후, 그의 복수와 진실을 찾기 위한 여정을 그린 스릴러.',120,'2003-11-21',5,'/img/영화_올드보이_포스터.jpg'),(10,'신의 한 수','장기(바둑)를 소재로 한 액션 영화로, 도박과 복수, 그리고 이를 둘러싼 인물들의 얽히고설킨 이야기를 다룬다.',118,'2014-07-03',5,'/img/영화_신의한수_포스터.jpg'),(11,'범죄도시','형사 마석도(마동석)가 강력반과 함께 거대한 범죄 조직과 맞서 싸우는 액션 영화. 범죄자들과의 치열한 전쟁을 통해 정의를 실현하는 이야기가 펼쳐진다.',121,'2017-10-03',5,'/img/영화_범죄도시_포스터.jpg'),(12,'택시운전사','1980년 광주 민주화 운동 당시를 배경으로, 독일 기자와 함께 광주로 향한 택시운전사(송강호)의 이야기를 그린 감동적인 드라마.',137,'2017-08-02',5,'/img/영화_택시운전사_포스터.jpg'),(13,'1987','1987년 민주화 항쟁을 배경으로, 한 대학생의 죽음과 이를 둘러싼 진실을 밝히려는 사람들의 이야기를 그린 영화.',129,'2017-12-27',5,'/img/영화_1987_포스터.jpg'),(14,'아가씨','1930년대 일제강점기를 배경으로 한 인물들 간의 복잡한 관계와 그로 인한 사건들을 다룬 스릴러.',145,'2016-06-01',5,'/img/영화_아가씨_포스터.jpg'),(15,'설국열차','지구가 얼어붙은 미래, 생존자들이 타고 있는 열차에서 벌어지는 계급 투쟁을 그린 디스토피아적 SF 영화.',126,'2013-08-01',5,'/img/영화_설국열차_포스터.jpg'),(16,'왕의 남자','조선시대를 배경으로, 광대 장생(감우성)과 공길(이준기)이 왕 앞에서 벌이는 극적인 이야기를 그린 영화.',119,'2005-12-29',5,'/img/영화_왕의남자_포스터.jpg'),(17,'곡성','한적한 마을에서 벌어지는 연쇄 살인 사건과 그 진실을 파헤치는 이야기.',156,'2016-05-12',5,'/img/영화_곡성_포스터.jpg'),(18,'극한직업','해체 위기의 마약반 형사들이 치킨집을 차리면서 벌어지는 유쾌한 코미디 영화.',111,'2019-01-23',5,'/img/영화_극한직업_포스터.jpg'),(19,'도둑들','국내외 최고의 도둑들이 모여 벌이는 대규모 범죄 작전을 그린 액션 영화.',135,'2012-07-25',5,'/img/영화_도둑들_포스터.jpg'),(20,'청년경찰','경찰대 학생 두 명이 우연히 목격한 납치 사건을 해결하려는 과정을 그린 코미디 액션 영화.',109,'2017-08-09',5,'/img/영화_청년경찰_포스터.jpg'),(21,'부산행','좀비 바이러스가 퍼진 열차에서 살아남기 위한 사람들의 사투를 그린 액션 스릴러.',118,'2016-07-20',5,'/img/영화_부산행_포스터.jpg');
/*!40000 ALTER TABLE `movies` ENABLE KEYS */;
